import React, { useState } from 'react';

const Login = () => {
  const [userRole, setUserRole] = useState('customer');

  return (
    <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '80vh' }}>
      <div style={{ background: 'white', padding: '40px', borderRadius: '15px', boxShadow: '0 5px 15px rgba(0,0,0,0.1)', width: '350px' }}>
        <h2 style={{ textAlign: 'center', color: '#0056b3' }}>Login</h2>
        
        <div style={{ display: 'flex', gap: '5px', marginBottom: '20px', background: '#f0f0f0', padding: '5px', borderRadius: '25px' }}>
          <button onClick={() => setUserRole('customer')} style={{ flex: 1, border: 'none', padding: '10px', borderRadius: '20px', cursor: 'pointer', background: userRole === 'customer' ? '#0056b3' : 'transparent', color: userRole === 'customer' ? 'white' : 'black' }}>User</button>
          <button onClick={() => setUserRole('business')} style={{ flex: 1, border: 'none', padding: '10px', borderRadius: '20px', cursor: 'pointer', background: userRole === 'business' ? '#0056b3' : 'transparent', color: userRole === 'business' ? 'white' : 'black' }}>MSME</button>
        </div>

        <form>
          <input type="text" placeholder="Email / Phone" style={{ width: '100%', padding: '12px', marginBottom: '15px', borderRadius: '8px', border: '1px solid #ddd' }} />
          <input type="password" placeholder="Password" style={{ width: '100%', padding: '12px', marginBottom: '20px', borderRadius: '8px', border: '1px solid #ddd' }} />
          <button style={{ width: '100%', padding: '12px', background: '#28a745', color: 'white', border: 'none', borderRadius: '25px', fontWeight: 'bold', cursor: 'pointer' }}>
            Login as {userRole}
          </button>
        </form>
      </div>
    </div>
  );
};

export default Login;
